"""HLD Patterns: Scaling Writes, Handling Large Blobs, Managing Long Running Tasks — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def scaling_writes_lesson() -> Lesson:
    return Lesson(id="hld-scaling-writes", number=113, title="Scaling Writes",
        focus=("sharding","write-ahead log","batching","LSM trees","async writes","partitioning"),
        overview="Scaling writes is harder than reads. Know sharding, batching, WAL, and write-optimized storage.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("sw-1","What is the most common approach to scaling writes?","medium",("scaling-writes",),("Sharding/partitioning data so writes distribute across multiple nodes","A protocol that batches multiple requests into a single TCP segment for efficiency","A security protocol that authenticates both client and server during the handshake","A consistency model where reads from any replica are guaranteed to be monotonically fresh"),0,"Sharding distributes write load. Each shard handles a subset of the total write traffic."),
        quiz("sw-2","Why are LSM trees write-optimized?","hard",("scaling-writes",),("Writes go to in-memory memtable (fast), then flush to sorted SSTables — sequential I/O instead of random","A transport layer optimization that reduces round-trip overhead using multiplexing","A connection management approach that pins clients to specific backend instances","A load shedding strategy that drops low-priority requests when resource utilization is high"),0,"LSM trees: O(1) memory writes + sequential disk flushes. Much faster writes than B-trees' random I/O."),
        quiz("sw-3","What is write batching?","medium",("scaling-writes",),("Accumulating multiple writes and committing them together to reduce per-write overhead","A communication pattern where services exchange messages through a centralized broker","Writing one row at a time across multiple service instances","A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests"),0,"Batching amortizes I/O overhead. Kafka batches messages; databases batch WAL entries."),
        quiz("sw-4","What is write-behind (async write) pattern?","hard",("scaling-writes",),("Buffer writes in memory/cache, acknowledge to client immediately, flush to storage asynchronously","A routing strategy that directs traffic based on geographic proximity of the client","A process that periodically reconciles state between systems to detect and fix drift","A serialization format that reduces cache entry size through schema-aware compression"),0,"Faster ack time but risks data loss if the buffer crashes before flushing."),
        quiz("sw-5","How does Kafka handle high write throughput?","hard",("scaling-writes",),("Append-only log per partition, sequential I/O, batching, zero-copy transfer, and OS page cache","A membership protocol where nodes periodically exchange state with random cluster peers","A partitioning algorithm that assigns data based on a hash of the geographic region","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool"),0,"Kafka's append-only design with sequential I/O achieves millions of writes/sec per broker."),
        quiz("sw-6","What is write amplification and why does it matter?","hard",("scaling-writes",),("A single logical write causes multiple physical I/O operations (e.g., index updates, LSM compaction)","A warming strategy that pre-loads data based on access frequency from the previous day","A transaction isolation level that prevents phantom reads using predicate locking","A scheduling algorithm that assigns tasks to workers based on estimated completion time"),0,"B-tree indexes cause write amplification. LSM trees reduce initial write cost but amplify during compaction."),
        quiz("sw-7","What is the hot partition problem for writes?","hard",("scaling-writes",),("One partition receives disproportionate writes, becoming a bottleneck despite overall capacity","A deployment strategy that gradually shifts traffic from the old version to the new one","A monitoring tool that tracks query execution plans and identifies slow running queries","A storage engine optimization that pre-sorts data on disk for sequential access patterns"),0,"Solution: salt the partition key, split hot partitions, or buffer writes and batch-apply."),
        quiz("sw-8","What is a write-ahead log (WAL)?","hard",("scaling-writes",),("Append changes to a sequential log before applying to main storage — ensures durability and enables replication","A cache coherence protocol that broadcasts invalidation messages to all cache tiers","A clock synchronization technique that uses NTP with bounded drift for ordering events","A schema design pattern that embeds frequently accessed data to avoid join overhead"),0,"WAL: sequential writes are fast. Main storage updated lazily. Crash recovery replays the log."),
        quiz("sw-9","How does CockroachDB scale writes?","hard",("scaling-writes",),("Raft-based consensus per range; data auto-sharded across ranges that split when too large","A state synchronization approach that reconciles differences using Merkle tree comparison","A prefetching algorithm that predicts future access patterns from recent query history","A consensus protocol that uses a rotating leader to distribute write coordination load"),0,"CockroachDB auto-splits ranges and distributes them. Each range is a Raft group."),
        quiz("sw-10","What is the dual-write problem?","hard",("scaling-writes",),("Writing to two systems (DB + cache/queue) without a transaction can leave them inconsistent if one fails","A persistence mechanism that snapshots the cache state to disk for crash recovery","A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A partitioning strategy that splits data based on a hash of the composite primary key"),0,"Solutions: outbox pattern, CDC, or transactional messaging to ensure both systems stay consistent."),
        quiz("sw-11","What is eventual consistency and how does it help scale writes?","medium",("scaling-writes",),("Accept that replicas may lag behind; acknowledge writes immediately without waiting for all replicas","A flow control mechanism that prevents the sender from overwhelming the receiver","A resilience pattern that isolates failures in one subsystem from propagating to others","Reads return latest write with automatic failover support"),0,"Eventual consistency lets you ack writes after 1 replica instead of waiting for all, reducing latency."),
        quiz("sw-12","How do you handle write contention on a single row?","hard",("scaling-writes",),("Use atomic operations (INCREMENT, CAS), optimistic locking, or distribute the counter across shards","A DNS-based technique that distributes queries across multiple authoritative servers","An index maintenance operation that rebuilds fragmented pages for better scan performance","A connection management approach that limits concurrent sessions to prevent overload"),0,"Sharded counters: split one counter into N shards. Read = SUM(all shards). Reduces contention."),
        quiz("sw-13","What is compaction in LSM trees?","hard",("scaling-writes",),("Merging and deduplicating sorted SSTables to reclaim space and improve read performance","A congestion avoidance algorithm that dynamically adjusts the transmission window","A data structure that stores cache metadata compactly using probabilistic counting","A sharding approach that distributes cached entries across nodes by consistent hashing"),0,"Compaction trades write amplification for better read performance and space efficiency."),
        quiz("sw-14","What is the commit log pattern?","medium",("scaling-writes",),("An append-only log of all changes — used by Kafka, databases, and event sourcing systems","A technique where the server pre-fetches resources based on predicted client needs","A replication technique that mirrors hot cache entries across multiple nodes for availability","A testing approach that injects controlled failures to verify system recovery behavior"),0,"Commit logs are the backbone of durable writes. Append-only = fast sequential I/O."),
        quiz("sw-15","How does DynamoDB handle write scaling?","hard",("scaling-writes",),("Auto-partitions data across storage nodes; provisioned or on-demand capacity scales write throughput","A replication strategy where writes go to any node and conflicts are resolved on read","A technique that partitions workload across worker pools based on resource requirements","A replication technique that synchronously mirrors writes to a standby for zero data loss"),0,"DynamoDB auto-splits partitions when throughput exceeds per-partition limits."),
        quiz("sw-16","What is a write-optimized database?","medium",("scaling-writes",),("A database designed for high write throughput (Cassandra, ScyllaDB) using LSM trees and append-only storage","A backup mechanism that captures incremental changes since the last full snapshot","A data pipeline stage that transforms and enriches events before writing to storage","A pattern where incoming requests are buffered and processed in priority-ordered batches"),0,"Write-optimized DBs sacrifice read performance for write speed. Read performance recovered via compaction."),
        quiz("sw-17","What is the leaderless replication approach to scaling writes?","hard",("scaling-writes",),("Write to multiple replicas directly (no leader); use quorum reads/writes for consistency","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds","An eviction algorithm that considers both recency and frequency when selecting victims","A query optimization strategy that rewrites subqueries into more efficient join patterns"),0,"DynamoDB/Cassandra: write to W replicas, read from R replicas. W+R>N ensures overlap."),
        quiz("sw-18","How do you handle burst writes?","medium",("scaling-writes",),("Use a message queue to buffer incoming writes and process them at a sustainable rate","Adding write-optimized secondary indexes to speed up the routing process","Deploying a hardware firewall to block incoming requests that exceed a set packet limit","Upgrading the server hardware specifications directly"),0,"Queue-based ingestion absorbs burst traffic and smooth writes to the database."),
        quiz("sw-19","What is time-partitioning for write scaling?","medium",("scaling-writes",),("Partition data by time period (hourly/daily tables) so writes always go to the newest partition","A backup process that copies table partitions to cold storage once per month","A cache eviction strategy that removes keys based on their creation timestamp","A sorting algorithm that orders query results chronologically in memory"),0,"Time-partitioning keeps write hot spot narrow and makes old data easy to archive."),
        quiz("sw-20","What is the change data capture (CDC) pattern for scaling writes?","hard",("scaling-writes",),("Capture DB changes from the WAL and stream them to downstream systems asynchronously","A backup utility that runs daily snapshots of database transaction logs","A database migration tool used to change table schemas without downtime","A caching policy that populates memory tables during application boot"),0,"CDC enables write scaling by asynchronously updating search indexes, caches, and analytics stores."),
    ))

def large_blobs_lesson() -> Lesson:
    return Lesson(id="hld-large-blobs", number=114, title="Handling Large Blobs",
        focus=("chunked upload","object storage","CDN","content-addressable","pre-signed URLs"),
        overview="Files, videos, and large objects need special handling. Know chunking, object storage, and CDN strategies.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("lb-1","How should you handle large file uploads?","hard",("large-blobs",),("Chunked upload: split into pieces, upload each with checksum, resume on failure","Transferring the entire file via standard FTP protocol to a centralized storage server","Sending the file payload in a single monolithic HTTP POST request with high timeouts","Compressing the file on the client using GZIP before uploading it as a single block"),0,"Chunked upload enables resumability, deduplication, and efficient bandwidth usage."),
        quiz("lb-2","What is content-addressable storage?","hard",("large-blobs",),("Addressing blocks by content hash (SHA-256), enabling deduplication across all users","A CDN caching strategy where files are distributed based on regional client request counts","A database indexing scheme that maps table rows to memory addresses based on primary keys","Storing files in a standard directory structure using their original names"),0,"Same content → same hash → store once, reference many times. Used by Dropbox, Git."),
        quiz("lb-3","What is a pre-signed URL?","medium",("large-blobs",),("A time-limited URL granting temporary access to upload/download from object storage without exposing credentials","A CDN endpoint configured to route client traffic to the nearest caching server","A bookmarked URL saved by the browser to skip the authentication redirect","A shortened URL redirecting to a long query path for analytics tracking"),0,"Pre-signed URLs let clients upload directly to S3, bypassing your server for large files."),
        quiz("lb-4","Why separate blob storage from metadata storage?","medium",("large-blobs",),("Blobs are large and best served by object storage (S3); metadata is small and needs indexing/querying (PostgreSQL)","To reduce cloud licensing costs by storing files in open-source databases","To improve read performance by caching raw files directly in Redis","There is no benefit; storing blobs inside relational tables simplifies transactions"),0,"Object storage: cheap, scalable, CDN-compatible. Database: queryable, consistent, transactional."),
        quiz("lb-5","What is the role of CDN in serving large files?","easy",("large-blobs",),("Caches files at edge locations near users, reducing latency and offloading origin servers","Routing client API requests to the closest backend database replica","Optimizing database index lookups by caching raw table records","Replicating database tables across multiple regions for data residency rules"),0,"CDNs serve images, videos, and static files from edge — reducing latency and origin load dramatically."),
        quiz("lb-6","How does chunked upload enable deduplication?","hard",("large-blobs",),("Each chunk is hashed independently; if the hash matches an existing chunk, skip the upload","Chunked upload has no relation to data deduplication","The CDN automatically deletes duplicate files from edge caches","The compression algorithm combines identical chunks into a single zip file"),0,"Content-defined chunking: even if one byte changes, only affected chunks need re-uploading."),
        quiz("lb-7","What is adaptive bitrate streaming for video?","hard",("large-blobs",),("Videos split into chunks at multiple qualities; player switches quality based on bandwidth (HLS/DASH)","The CDN automatically adjusts file formats based on user browser types","The backend database server scales its container pool based on video stream volume","Serving a single high-quality video file that is compressed on demand"),0,"HLS/DASH: manifest lists chunk URLs at each quality. Player monitors bandwidth and switches dynamically."),
        quiz("lb-8","What is HLS (HTTP Live Streaming)?","hard",("large-blobs",),("Apple's streaming protocol: video split into small .ts segments, served via HTTP, with m3u8 manifest","A database protocol optimized for streaming query results to client applications","A CDN edge routing feature designed to balance video playback traffic","A WebSocket extension that supports binary frame fragmentation for files"),0,"HLS: divide video into 2-10 second segments. Client downloads manifest, then segments sequentially."),
        quiz("lb-9","How does Dropbox sync files efficiently?","hard",("large-blobs",),("Content-defined chunking with rolling hash; only changed chunks are uploaded/downloaded","Sending file differences as email attachments to a centralized parsing server","Running a background cron script that executes standard FTP synchronization","Uploading the entire file to the server on every local modification"),0,"Rsync-like: detect changed blocks using rolling hash, transfer only deltas."),
        quiz("lb-10","What is the multipart upload pattern in S3?","medium",("large-blobs",),("Upload large files in parts independently; S3 assembles them; parts can be retried individually","A backup policy that copies S3 objects to multiple cold storage tiers","A versioning system that preserves previous revisions of modified files","Uploading multiple distinct files simultaneously within a single request"),0,"Multipart: initiate → upload parts (parallel OK) → complete. Failed parts retry without restarting."),
        quiz("lb-11","What is the difference between S3, GCS, and Azure Blob Storage?","medium",("large-blobs",),("Functionally similar object stores; S3 API is the de facto standard that GCS/Azure also support","Only Amazon S3 supports horizontal scaling for multi-terabyte files","They use entirely different underlying hardware architectures that prevent API compatibility","They share a centralized cloud storage pool managed by a global consortium"),0,"S3 is the standard. MinIO provides S3-compatible self-hosted object storage."),
        quiz("lb-12","What is video transcoding and why is it needed?","medium",("large-blobs",),("Converting uploaded video into multiple formats/resolutions for different devices and network conditions","A CDN edge caching optimization that compresses video files dynamically","A streaming protocol designed to transmit raw video over UDP channels","A compression algorithm that reduces video files without changing formats"),0,"Transcode to 480p/720p/1080p/4K + different codecs (H.264, VP9, AV1) for universal playback."),
        quiz("lb-13","How do you handle image resizing at scale?","hard",("large-blobs",),("Generate on-demand and cache: when a size is first requested, resize, cache in CDN, serve cached thereafter","Pre-generating every conceivable image size and storing them in object storage","Requiring the client browser to resize large images via CSS properties","Storing only the high-resolution original image and resizing it on the main server every read"),0,"On-demand resizing with CDN caching: URL like /images/photo.jpg?w=300&h=300 → resize → cache."),
        quiz("lb-14","What is the thumbnail generation pattern?","medium",("large-blobs",),("Upload → async job generates thumbnails at standard sizes → store in object storage → serve via CDN","Generating thumbnails in real-time on the client using HTML5 Canvas","Requiring administrators to manually upload thumb versions of each image","Using a database trigger that resizes binary fields synchronously during insert"),0,"Async processing: upload triggers a job queue. Workers generate thumbnails. CDN serves them."),
        quiz("lb-15","What is the challenge of serving large files globally?","medium",("large-blobs",),("Latency — files must be cached at edge locations worldwide; origin requests must be minimized","The high cost of cloud egress fees across different network regions","Operating systems limits on maximum file size downloads over HTTP","Enforcing encryption keys for data in transit across international zones"),0,"CDN + multi-region replication + intelligent cache warming for popular content."),
        quiz("lb-16","How does YouTube handle video storage at scale?","hard",("large-blobs",),("Distributed object storage with redundancy, multiple encoded versions per video, CDN for delivery","Storing all video files on a single massive mainframe server with redundant power","Writing files to local server hard drives without replication or CDN caching","Concentrating all storage servers in a single data center in the United States"),0,"Google's Colossus stores video. Each video has multiple bitrate versions. Served from global CDN."),
        quiz("lb-17","What is the garbage collection challenge in blob storage?","hard",("large-blobs",),("Identifying and deleting orphaned blobs (referenced chunks with no parent, or deleted files' chunks)","A CDN edge caching eviction problem where files are deleted too early","Reclaiming application server RAM by running garbage collection on big objects","A network connection leak caused by unclosed file streams"),0,"If metadata is deleted but blob isn't (or vice versa), you leak storage or break references."),
        quiz("lb-18","What is the role of checksums in blob storage?","medium",("large-blobs",),("Verify data integrity during upload, transfer, and storage — detect corruption or tampering","Encrypting file contents to prevent unauthorized access by third parties","Providing the hash key used to identify duplicate files in the index","Compressing file headers to reduce transmission latency over TCP"),0,"MD5/SHA-256 checksums ensure the file you uploaded is the exact file stored and served."),
        quiz("lb-19","How do you implement resumable uploads?","hard",("large-blobs",),("Track uploaded chunks on server; client queries which chunks are missing and uploads only those","Configuring a standard FTP client that automatically restarts aborted uploads","Caching file parts in the browser memory and retrying the whole request later","Requiring the client to start the entire upload from the beginning after a drop"),0,"Client: upload chunk → get ack. On failure: ask server which chunks received → resume from there."),
        quiz("lb-20","What is the difference between hot and cold storage tiers?","medium",("large-blobs",),("Hot: frequently accessed, fast, expensive (SSD/S3 Standard). Cold: rarely accessed, slow, cheap (S3 Glacier)","Hot storage holds older data that is read frequently; cold storage holds new writes","Cold storage uses superior hardware-level encryption to secure confidential files","The temperature at which the physical storage drives are maintained in datacenters"),0,"Lifecycle policies auto-move old data to cheaper tiers. Access old data with higher latency."),
    ))

def long_running_tasks_lesson() -> Lesson:
    return Lesson(id="hld-long-tasks", number=115, title="Managing Long Running Tasks",
        focus=("job queues","workers","idempotency","progress tracking","timeouts","dead letter queues"),
        overview="Long-running tasks (video processing, reports, ML inference) need special architecture patterns.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("lt-1","How should you handle a request that takes minutes to process?","medium",("long-tasks",),("Return 202 Accepted with a job ID; process async; client polls for status or receives webhook callback","Upgrading the application server hardware to reduce processing time","Holding the client connection open and letting the browser wait until finished","Increasing the gateway proxy and client browser timeout limits"),0,"Never block a client for minutes. Accept the request, process in background, notify when done."),
        quiz("lt-2","What is a job/task queue?","easy",("long-tasks",),("A queue where producers submit jobs and workers consume and process them asynchronously","A load balancer configuration that distributes web queries round-robin","A memory caching layer that stores compiled query results","A relational database table containing user session details"),0,"Job queues (Celery, Sidekiq, Bull) decouple request handling from processing."),
        quiz("lt-3","What is the competing consumers pattern?","medium",("long-tasks",),("Multiple workers read from the same queue, each processing different jobs for parallelism","A caching strategy where multiple edge nodes compete for bandwidth","A database lock resolution protocol that handles transaction skew","A relational table partitioning scheme that distributes write load"),0,"Add more workers to increase throughput. Each job processed by exactly one worker."),
        quiz("lt-4","How do you handle worker failures?","hard",("long-tasks",),("Use visibility timeouts: if worker doesn't ack within timeout, job returns to queue for another worker","Deleting the job from the queue immediately upon detecting worker connection loss","Ignoring worker failures and letting the client time out naturally","Restarting the main application server whenever a background worker crashes"),0,"SQS visibility timeout: job is invisible while processing. If no ack, it reappears for retry."),
        quiz("lt-5","What is a dead letter queue?","medium",("long-tasks",),("Where jobs that fail after max retries are sent for investigation and manual handling","A logging file where exception stack traces are saved sequentially","A replication backup queue used to mirror messages across datacenters","A temporary buffer containing messages deleted by database users"),0,"DLQs prevent poison messages from blocking the queue forever."),
        quiz("lt-6","How do you track progress of long-running tasks?","medium",("long-tasks",),("Store progress in a fast store (Redis); expose a status endpoint; optionally push updates via WebSocket","Sending automated email updates to the user at fixed percentage steps","There is no standard way; clients must assume the job takes a fixed time","Requiring administrators to read the raw worker log files directly"),0,"Job writes progress (30%, 50%, 90%) to Redis. Client polls /jobs/{id}/status or subscribes via WS."),
        quiz("lt-7","What is the fan-out/fan-in pattern for long tasks?","hard",("long-tasks",),("Split a large task into many subtasks (fan-out), process in parallel, aggregate results (fan-in)","A caching strategy where queries are broadcast to all cache nodes","A database partitioning pattern that clusters tables by creation date","A load balancing technique that splits client queries across replicas"),0,"Map-Reduce is a classic fan-out/fan-in. Video transcoding: split into chunks → process → merge."),
        quiz("lt-8","Why must long-running tasks be idempotent?","hard",("long-tasks",),("Workers may crash and jobs get retried — without idempotency, you get duplicate processing/side effects","To reduce CPU consumption on the background worker instances","To ensure the user interface displays progress indicators accurately","It is not necessary, as task schedulers guarantee exactly-once execution"),0,"Idempotent tasks are safe to retry. Use a unique job ID to detect and skip duplicates."),
        quiz("lt-9","What is a priority queue for long tasks?","medium",("long-tasks",),("A queue where jobs are processed based on priority level, not just arrival order","A database indexing scheme that sorts records by high write activity","A cache eviction policy that prioritizes hot keys over cold keys","A standard FIFO queue that distributes tasks based on arrival timestamps"),0,"High-priority jobs (paid users, time-sensitive) get processed before low-priority (batch reports)."),
        quiz("lt-10","How do you handle job timeouts?","hard",("long-tasks",),("Set a maximum execution time; if exceeded, kill the worker, mark job as failed, retry or move to DLQ","Disabling timeout limits and letting background processes run indefinitely","Throwing a client-side exception that requires the user to resubmit the job","Enlarging the gateway connection timeout limit proportionally to the file size"),0,"Timeouts prevent zombie workers from holding resources. Set reasonable limits per job type."),
        quiz("lt-11","What is the circuit breaker pattern for long tasks?","hard",("long-tasks",),("If a downstream service repeatedly fails, stop submitting jobs to it temporarily, fail fast instead","A database feature that aborts transactions exceeding a lock timeout","A queue configuration that processes messages based on their priority level","A physical fuse installed in server racks to prevent electrical overload"),0,"Circuit breaker: open after N failures → fail fast → half-open after cooldown → test → close."),
        quiz("lt-12","How does video transcoding use long-running task patterns?","hard",("long-tasks",),("Upload → queue → worker splits video into chunks → parallel transcoding → merge → store → notify","Executing all resizing and compression in the user's browser via JS","Transcoding the video in real-time as the stream is received by the proxy","Processing the entire video file on a single thread to maintain frame order"),0,"Fan-out/fan-in: each chunk transcoded independently. Horizontally scalable with more workers."),
        quiz("lt-13","What is exponential backoff for job retries?","medium",("long-tasks",),("Wait increasing durations between retries (1s, 2s, 4s, 8s...) with jitter to avoid synchronized retries","Retrying the operation immediately at a constant sub-second frequency","Increasing the delay between retries linearly (1s, 2s, 3s, 4s...)","Disabling retry configurations and reporting a failure immediately"),0,"Exponential backoff reduces load on failing services. Jitter prevents retry storms."),
        quiz("lt-14","What is the scheduler pattern for recurring long tasks?","medium",("long-tasks",),("A service that triggers jobs at scheduled times (cron-like) using a distributed scheduler","Requiring system operators to run command scripts manually","A background daemon that pre-loads cache tables during boot","A load balancer configuration that routes user login requests"),0,"Distributed schedulers (Celery Beat, Airflow) ensure jobs run on time across multiple nodes."),
        quiz("lt-15","How do you ensure exactly-once job processing?","hard",("long-tasks",),("At-least-once delivery + idempotent workers: use job ID deduplication to skip already-processed jobs","Using a distributed transaction protocol like two-phase commit","It is mathematically impossible under all network configurations","Pinning all task queues to a single worker server to prevent concurrency"),0,"Store completed job IDs. Before processing, check if ID exists. If yes, skip."),
        quiz("lt-16","What is the poison message problem?","hard",("long-tasks",),("A message that causes worker crashes on every attempt, blocking the queue for all other messages","A malicious payload that exploits SQL injection bugs in database queries","A corrupt table row that breaks index structures during writes","A network routing collision that sends messages to incorrect destinations"),0,"Solutions: max retry count + DLQ. After N failures, move to DLQ for investigation."),
        quiz("lt-17","How do you scale video processing workers?","medium",("long-tasks",),("Auto-scale worker fleet based on queue depth; more pending jobs = more workers","Scaling up the hardware specifications of the single worker instance","Maintaining a fixed pool size of worker servers under all traffic loads","Delegating the transcoding processing to client devices via WebAssembly"),0,"Cloud auto-scaling: monitor queue length. Scale up when queue grows. Scale down when queue drains."),
        quiz("lt-18","What is the bulkhead pattern for long tasks?","hard",("long-tasks",),("Isolate different task types into separate queues/worker pools so one type's failure doesn't affect others","A caching policy that separates read and write segments in memory","A database sharding scheme that partitions tables by geographic region","A storage engine optimization that writes sequential files to SSD"),0,"Separate queues for video, image, report processing. Failure in video queue doesn't block images."),
        quiz("lt-19","What is a workflow orchestrator (Temporal/Airflow)?","hard",("long-tasks",),("A platform managing complex multi-step workflows with built-in state persistence, retry, and timeout handling","A load balancer that routes traffic based on server resource usage","A continuous integration pipeline tool used to deploy applications","A relational database specialized in storing transaction logs"),0,"Temporal: define workflows as code. Handles retries, timeouts, compensation, and state automatically."),
        quiz("lt-20","What is the difference between synchronous and asynchronous task execution?","easy",("long-tasks",),("Sync: caller waits for result. Async: caller gets immediate response; result delivered later via callback/poll","Synchronous execution is always faster since it bypasses queue overhead","Asynchronous execution cannot return computation results back to the client","There is no difference in execution flow; they differ only in memory usage"),0,"Rule of thumb: if it takes >1s, make it async. Never block an HTTP handler for minutes."),
    ))
